/**
 * Handles starting a single-player game in CollabMatch.
 *
 * @module     mod_collabmatch/start_single_player
 * @copyright  2026 Johan Venter <johan@myfutureway.co.za>
 * @license    http://www.gnu.org/copyleft/gpl.html GNU GPL v3 or later
 */
define("mod_collabmatch/start_single_player",["core/ajax","core/notification","core/str"],function(Ajax,Notification,Str){"use strict";return{init:function(cmid){var buttons=document.querySelectorAll("[data-start-single-player]");if(!buttons.length){return}buttons.forEach(function(button){button.addEventListener("click",function(e){e.preventDefault();if(button.disabled){return}button.disabled=true;Ajax.call([{methodname:"mod_collabmatch_start_single_player",args:{cmid:cmid}}])[0].then(function(response){if(response&&response.success){window.location.reload();return}button.disabled=false;return Promise.all([Str.get_string("pluginname","mod_collabmatch"),Str.get_string("jssingleplayerstartfailed","mod_collabmatch"),Str.get_string("ok","moodle")]).then(function(strings){Notification.alert(strings[0],strings[1],strings[2])})}).catch(function(error){button.disabled=false;Notification.exception(error)})})})}}});